import { useState, useEffect, useRef } from "react";

/**
 * Adds a "show" class when element enters viewport,
 * triggering the .fade CSS transition.
 */
export function useFadeIn() {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          el.classList.add("show");
          observer.unobserve(el);
        }
      },
      { threshold: 0.12 }
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  return ref;
}

/**
 * Cycles through an array of strings with a typewriter effect.
 * @param {string[]} words - array of strings to cycle through
 * @param {number}   speed - ms per character when typing
 */
export function useTypingEffect(words, speed = 80) {
  const [text,     setText]     = useState("");
  const [wordIdx,  setWordIdx]  = useState(0);
  const [charIdx,  setCharIdx]  = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const current = words[wordIdx];
    const isFullyTyped   = !deleting && charIdx === current.length;
    const isFullyDeleted = deleting  && charIdx === 0;

    const delay = deleting
      ? 40
      : isFullyTyped
        ? 2400   // pause before deleting
        : speed;

    const timer = setTimeout(() => {
      if (!deleting && !isFullyTyped) {
        setText(current.slice(0, charIdx + 1));
        setCharIdx(c => c + 1);
      } else if (isFullyTyped) {
        setDeleting(true);
      } else if (deleting && !isFullyDeleted) {
        setText(current.slice(0, charIdx - 1));
        setCharIdx(c => c - 1);
      } else {
        setDeleting(false);
        setWordIdx(i => (i + 1) % words.length);
      }
    }, delay);

    return () => clearTimeout(timer);
  }, [text, charIdx, deleting, wordIdx, words, speed]);

  return text;
}
